import { jest } from '@jest/globals';
import TerminalInterface from '../src/cli/TerminalInterface.js';

describe('TerminalInterface', () => {
  let terminal;

  beforeEach(() => {
    terminal = new TerminalInterface();
    // Suppress console output during tests
    jest.spyOn(console, 'log').mockImplementation(() => {});
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  describe('constructor', () => {
    it('should initialize with default values', () => {
      expect(terminal.commandHistory).toEqual([]);
      expect(terminal.historyIndex).toBe(-1);
      expect(terminal.spinner).toBeNull();
      expect(terminal.isRunning).toBe(false);
    });

    it('should accept config parameter', () => {
      const config = { theme: 'dark' };
      const terminalWithConfig = new TerminalInterface(config);
      expect(terminalWithConfig.config).toEqual(config);
    });
  });

  describe('start', () => {
    it('should set isRunning to true', async () => {
      await terminal.start();
      expect(terminal.isRunning).toBe(true);
    });

    it('should display welcome message', async () => {
      await terminal.start();
      expect(console.log).toHaveBeenCalled();
      const calls = console.log.mock.calls.map(call => call[0]);
      const welcomeText = calls.join('');
      expect(welcomeText).toContain('Codestral');
    });
  });

  describe('command history', () => {
    it('should add commands to history', () => {
      terminal.commandHistory.push('command1');
      terminal.commandHistory.push('command2');
      expect(terminal.getHistory()).toEqual(['command1', 'command2']);
    });

    it('should get previous command', () => {
      terminal.commandHistory = ['cmd1', 'cmd2', 'cmd3'];
      terminal.historyIndex = 3;
      
      expect(terminal.getPreviousCommand()).toBe('cmd3');
      expect(terminal.getPreviousCommand()).toBe('cmd2');
      expect(terminal.getPreviousCommand()).toBe('cmd1');
    });

    it('should not go before first command', () => {
      terminal.commandHistory = ['cmd1', 'cmd2'];
      terminal.historyIndex = 1;
      
      terminal.getPreviousCommand();
      const result = terminal.getPreviousCommand();
      expect(result).toBe('cmd1');
      expect(terminal.historyIndex).toBe(0);
    });

    it('should get next command', () => {
      terminal.commandHistory = ['cmd1', 'cmd2', 'cmd3'];
      terminal.historyIndex = 0;
      
      expect(terminal.getNextCommand()).toBe('cmd2');
      expect(terminal.getNextCommand()).toBe('cmd3');
    });

    it('should return empty string at end of history', () => {
      terminal.commandHistory = ['cmd1', 'cmd2'];
      terminal.historyIndex = 1;
      
      const result = terminal.getNextCommand();
      expect(result).toBe('');
      expect(terminal.historyIndex).toBe(2);
    });

    it('should return null for empty history', () => {
      expect(terminal.getPreviousCommand()).toBeNull();
      expect(terminal.getNextCommand()).toBeNull();
    });

    it('should clear history', () => {
      terminal.commandHistory = ['cmd1', 'cmd2'];
      terminal.historyIndex = 1;
      
      terminal.clearHistory();
      
      expect(terminal.commandHistory).toEqual([]);
      expect(terminal.historyIndex).toBe(-1);
    });
  });

  describe('stop', () => {
    it('should set isRunning to false', () => {
      terminal.isRunning = true;
      terminal.stop();
      expect(terminal.isRunning).toBe(false);
    });

    it('should stop spinner if running', () => {
      terminal.spinner = { stop: jest.fn() };
      terminal.stop();
      expect(terminal.spinner.stop).toHaveBeenCalled();
    });
  });

  describe('display', () => {
    it('should display text content', () => {
      terminal.display('Hello World');
      expect(console.log).toHaveBeenCalledWith('Hello World');
    });

    it('should display error messages in red', () => {
      terminal.display('Error message', { type: 'error' });
      expect(console.log).toHaveBeenCalled();
    });

    it('should display success messages in green', () => {
      terminal.display('Success message', { type: 'success' });
      expect(console.log).toHaveBeenCalled();
    });

    it('should display warning messages in yellow', () => {
      terminal.display('Warning message', { type: 'warning' });
      expect(console.log).toHaveBeenCalled();
    });

    it('should display info messages in blue', () => {
      terminal.display('Info message', { type: 'info' });
      expect(console.log).toHaveBeenCalled();
    });

    it('should apply syntax highlighting when requested', () => {
      const code = 'const x = 10;';
      terminal.display(code, { highlight: true, language: 'javascript' });
      expect(console.log).toHaveBeenCalled();
    });

    it('should handle syntax highlighting errors gracefully', () => {
      const code = 'invalid code';
      terminal.display(code, { highlight: true, language: 'unknown' });
      expect(console.log).toHaveBeenCalled();
    });
  });

  describe('displayCode', () => {
    it('should display code with borders', () => {
      terminal.displayCode('const x = 10;', 'javascript');
      expect(console.log).toHaveBeenCalledTimes(3); // Border, code, border
    });
  });

  describe('displayError', () => {
    it('should display error message', () => {
      terminal.displayError('Something went wrong');
      expect(console.log).toHaveBeenCalled();
    });

    it('should display stack trace in debug mode', () => {
      terminal.config.debug = true;
      const error = new Error('Test error');
      terminal.displayError('Error occurred', error);
      expect(console.log).toHaveBeenCalled();
    });
  });

  describe('displaySuccess', () => {
    it('should display success message with checkmark', () => {
      terminal.displaySuccess('Operation completed');
      expect(console.log).toHaveBeenCalled();
    });
  });

  describe('displayWarning', () => {
    it('should display warning message', () => {
      terminal.displayWarning('Be careful');
      expect(console.log).toHaveBeenCalled();
    });
  });

  describe('displayInfo', () => {
    it('should display info message', () => {
      terminal.displayInfo('Information');
      expect(console.log).toHaveBeenCalled();
    });
  });

  describe('spinner', () => {
    it('should show spinner with message', () => {
      terminal.showSpinner('Loading...');
      expect(terminal.spinner).not.toBeNull();
      terminal.hideSpinner();
    });

    it('should hide spinner', () => {
      terminal.showSpinner('Loading...');
      terminal.hideSpinner();
      expect(terminal.spinner).toBeNull();
    });

    it('should hide spinner with success message', () => {
      terminal.showSpinner('Loading...');
      terminal.hideSpinner('Done!', true);
      expect(terminal.spinner).toBeNull();
    });

    it('should hide spinner with failure message', () => {
      terminal.showSpinner('Loading...');
      terminal.hideSpinner('Failed!', false);
      expect(terminal.spinner).toBeNull();
    });

    it('should update spinner text', () => {
      terminal.showSpinner('Loading...');
      terminal.updateSpinner('Still loading...');
      expect(terminal.spinner.text).toBe('Still loading...');
      terminal.hideSpinner();
    });

    it('should stop existing spinner when showing new one', () => {
      terminal.showSpinner('First');
      const firstSpinner = terminal.spinner;
      terminal.showSpinner('Second');
      expect(terminal.spinner).not.toBe(firstSpinner);
      terminal.hideSpinner();
    });
  });

  describe('terminal resize', () => {
    it('should handle resize events', () => {
      terminal.handleResize();
      const size = terminal.getTerminalSize();
      expect(size.width).toBeDefined();
      expect(size.height).toBeDefined();
    });

    it('should get terminal size', () => {
      const size = terminal.getTerminalSize();
      expect(size).toHaveProperty('width');
      expect(size).toHaveProperty('height');
      expect(typeof size.width).toBe('number');
      expect(typeof size.height).toBe('number');
    });
  });

  describe('syntax highlighting config', () => {
    it('should enable syntax highlighting by default', () => {
      const term = new TerminalInterface();
      expect(term.syntaxHighlight).toBe(true);
    });

    it('should respect syntaxHighlight config', () => {
      const term = new TerminalInterface({ syntaxHighlight: false });
      expect(term.syntaxHighlight).toBe(false);
    });
  });

  describe('interrupt handling', () => {
    let processOnSpy;
    let processRemoveListenerSpy;
    let processExitSpy;

    beforeEach(() => {
      processOnSpy = jest.spyOn(process, 'on');
      processRemoveListenerSpy = jest.spyOn(process, 'removeListener');
      processExitSpy = jest.spyOn(process, 'exit').mockImplementation(() => {});
    });

    afterEach(() => {
      processOnSpy.mockRestore();
      processRemoveListenerSpy.mockRestore();
      processExitSpy.mockRestore();
    });

    it('should register interrupt handler', () => {
      terminal.handleInterrupt();
      expect(processOnSpy).toHaveBeenCalledWith('SIGINT', expect.any(Function));
      expect(terminal.interruptHandler).not.toBeNull();
    });

    it('should register interrupt handler with callback', () => {
      const callback = jest.fn();
      terminal.handleInterrupt(callback);
      expect(terminal.onInterruptCallback).toBe(callback);
    });

    it('should remove existing handler before adding new one', () => {
      terminal.handleInterrupt();
      const firstHandler = terminal.interruptHandler;
      
      terminal.handleInterrupt();
      
      expect(processRemoveListenerSpy).toHaveBeenCalledWith('SIGINT', firstHandler);
    });

    it('should execute callback on interrupt', async () => {
      const callback = jest.fn().mockResolvedValue();
      terminal.handleInterrupt(callback);
      
      // Trigger the interrupt handler
      await terminal.interruptHandler();
      
      expect(callback).toHaveBeenCalled();
    });

    it('should handle callback errors gracefully', async () => {
      const consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation();
      const callback = jest.fn().mockRejectedValue(new Error('Callback error'));
      terminal.handleInterrupt(callback);
      
      // Trigger the interrupt handler
      await terminal.interruptHandler();
      
      expect(consoleErrorSpy).toHaveBeenCalled();
      consoleErrorSpy.mockRestore();
    });

    it('should stop spinner on interrupt', async () => {
      terminal.showSpinner('Loading...');
      terminal.handleInterrupt();
      
      await terminal.interruptHandler();
      
      expect(terminal.spinner).toBeNull();
    });

    it('should call gracefulShutdown on interrupt', async () => {
      const gracefulShutdownSpy = jest.spyOn(terminal, 'gracefulShutdown');
      terminal.handleInterrupt();
      
      await terminal.interruptHandler();
      
      expect(gracefulShutdownSpy).toHaveBeenCalled();
      gracefulShutdownSpy.mockRestore();
    });

    it('should remove interrupt handler', () => {
      terminal.handleInterrupt();
      const handler = terminal.interruptHandler;
      
      terminal.removeInterruptHandler();
      
      expect(processRemoveListenerSpy).toHaveBeenCalledWith('SIGINT', handler);
      expect(terminal.interruptHandler).toBeNull();
      expect(terminal.onInterruptCallback).toBeNull();
    });

    it('should handle removeInterruptHandler when no handler exists', () => {
      terminal.removeInterruptHandler();
      expect(terminal.interruptHandler).toBeNull();
    });

    it('should remove interrupt handler on stop', () => {
      terminal.handleInterrupt();
      const removeHandlerSpy = jest.spyOn(terminal, 'removeInterruptHandler');
      
      terminal.stop();
      
      expect(removeHandlerSpy).toHaveBeenCalled();
      removeHandlerSpy.mockRestore();
    });
  });

  describe('gracefulShutdown', () => {
    let processExitSpy;

    beforeEach(() => {
      processExitSpy = jest.spyOn(process, 'exit').mockImplementation(() => {});
    });

    afterEach(() => {
      processExitSpy.mockRestore();
    });

    it('should stop terminal interface', async () => {
      terminal.isRunning = true;
      
      await terminal.gracefulShutdown();
      
      expect(terminal.isRunning).toBe(false);
    });

    it('should exit process with code 0', async () => {
      await terminal.gracefulShutdown();
      
      expect(processExitSpy).toHaveBeenCalledWith(0);
    });

    it('should display goodbye message', async () => {
      await terminal.gracefulShutdown();
      
      expect(console.log).toHaveBeenCalled();
      const calls = console.log.mock.calls.map(call => call[0]).join('');
      expect(calls).toContain('Goodbye');
    });
  });
});
